function deepenArticle(post: BatchArticle) {
  return `${post.body}${ARTICLE_ADDENDA[post.id] ?? ''}${ARTICLE_FINAL_NOTES[post.id] ?? ''}${ARTICLE_MICRO_CASES[post.id] ?? ''}${ARTICLE_RANKING_POLISH[post.id] ?? ''}`
}

export const GENERATED_POSTS_30_BATCH2: Post[] = BASE_POSTS_30_BATCH2.map(post => ({
  ...post,
  body: deepenArticle(post),
}))
